head.b:skin:
/*----------------------------------------------
  FRESHNEWS - DailyHunt Style Blogger Template
----------------------------------------------*/

:root {
  --bg-primary: #f0f2f5;
  --bg-card: #ffffff;
  --bg-header: #ffffff;
  --text-primary: #1a1a2e;
  --text-secondary: #555770;
  --text-muted: #8e8ea0;
  --accent: #e63946;
  --accent-hover: #c1121f;
  --accent-gradient: linear-gradient(135deg, #e63946, #ff6b6b);
  --border: #e4e6eb;
  --shadow-sm: 0 1px 3px rgba(0,0,0,0.06);
  --shadow-md: 0 4px 12px rgba(0,0,0,0.08);
  --shadow-lg: 0 8px 30px rgba(0,0,0,0.12);
  --shadow-hover: 0 12px 40px rgba(0,0,0,0.15);
  --radius: 16px;
  --radius-sm: 10px;
  --transition: 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --font-ml: 'Noto Sans Malayalam', sans-serif;
  --font-en: 'Inter', sans-serif;
  --ticker-bg: #1a1a2e;
  --badge-trending: linear-gradient(135deg, #ff6b6b, #ee5a24);
  --badge-breaking: linear-gradient(135deg, #e63946, #b71c1c);
  --badge-latest: linear-gradient(135deg, #00b894, #00cec9);
}

[data-theme="dark"] {
  --bg-primary: #0d1117;
  --bg-card: #161b22;
  --bg-header: #161b22;
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #6e7681;
  --border: #30363d;
  --shadow-sm: 0 1px 3px rgba(0,0,0,0.3);
  --shadow-md: 0 4px 12px rgba(0,0,0,0.4);
  --shadow-lg: 0 8px 30px rgba(0,0,0,0.5);
  --shadow-hover: 0 12px 40px rgba(0,0,0,0.6);
  --ticker-bg: #0d1117;
}

/* ===== RESET ===== */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--font-ml);
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  transition: background var(--transition), color var(--transition);
}
a { text-decoration: none; color: inherit; }
img { max-width: 100%; height: auto; display: block; }

/* ===== HEADER ===== */
.dh-header {
  position: sticky; top: 0; z-index: 1000;
  background: var(--bg-header);
  border-bottom: 1px solid var(--border);
  backdrop-filter: blur(20px);
}
.dh-header-inner {
  max-width: 1280px; margin: 0 auto;
  padding: 12px 20px;
  display: flex; align-items: center; justify-content: space-between;
}
.dh-logo { display: flex; align-items: center; gap: 10px; }
.dh-logo-icon {
  width: 40px; height: 40px;
  background: var(--accent-gradient); border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  color: #fff; font-size: 22px; font-weight: 800; font-family: var(--font-en);
  box-shadow: 0 4px 15px rgba(230,57,70,0.3);
}
.dh-logo-text {
  font-family: var(--font-en); font-size: 22px; font-weight: 800;
  background: var(--accent-gradient);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  background-clip: text;
}
.dh-header-actions { display: flex; align-items: center; gap: 8px; }
.dh-btn-icon {
  width: 40px; height: 40px; border-radius: 50%; border: none;
  background: transparent; color: var(--text-secondary); cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  transition: all var(--transition); font-size: 22px;
}
.dh-btn-icon:hover { background: var(--bg-primary); color: var(--accent); }

/* ===== TICKER ===== */
.dh-ticker {
  background: var(--ticker-bg); color: #fff;
  overflow: hidden; height: 38px;
  display: flex; align-items: center;
}
.dh-ticker-label {
  background: var(--accent-gradient); color: #fff;
  padding: 0 14px; height: 100%;
  display: flex; align-items: center;
  font-family: var(--font-en); font-size: 11px; font-weight: 700;
  letter-spacing: 1.2px; text-transform: uppercase;
  white-space: nowrap; z-index: 2; position: relative;
}
.dh-ticker-label::after {
  content: ''; position: absolute; right: -12px; top: 0;
  border-style: solid; border-width: 19px 0 19px 12px;
  border-color: transparent transparent transparent var(--accent);
}
.dh-ticker-content {
  display: flex; animation: tickerScroll 30s linear infinite;
  padding-left: 20px;
}
.dh-ticker-item { white-space: nowrap; padding: 0 40px; font-size: 13px; font-weight: 500; }
.dh-ticker-item::before { content: '•'; color: var(--accent); margin-right: 10px; }
@keyframes tickerScroll {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

/* ===== CATEGORIES ===== */
.dh-categories {
  background: var(--bg-header);
  border-bottom: 1px solid var(--border);
  overflow-x: auto; scrollbar-width: none;
}
.dh-categories::-webkit-scrollbar { display: none; }
.dh-categories-inner {
  max-width: 1280px; margin: 0 auto; padding: 0 16px;
  display: flex; gap: 4px;
}
.dh-cat-tab {
  padding: 12px 18px; font-size: 13.5px; font-weight: 600;
  color: var(--text-secondary); white-space: nowrap;
  border-bottom: 3px solid transparent; transition: all var(--transition);
}
.dh-cat-tab:hover { color: var(--accent); }
.dh-cat-tab.active { color: var(--accent); border-bottom-color: var(--accent); }

/* ===== MAIN ===== */
.dh-main { max-width: 1280px; margin: 0 auto; padding: 20px 16px; }

/* ===== NEWS GRID ===== */
.dh-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
  gap: 20px;
}

/* ===== FIRST CARD (hero) via CSS ===== */
.dh-grid .dh-card:first-child {
  grid-column: 1 / -1;
}
.dh-grid .dh-card:first-child .dh-card-img-wrap {
  padding-top: 45%;
}
.dh-grid .dh-card:first-child .dh-card-title {
  font-size: 24px;
}

/* ===== NEWS CARD ===== */
.dh-card {
  background: var(--bg-card); border-radius: var(--radius);
  overflow: hidden; box-shadow: var(--shadow-sm);
  transition: all var(--transition); cursor: pointer;
  border: 1px solid var(--border);
}
.dh-card:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-hover); border-color: transparent;
}
.dh-card-link { display: block; color: inherit; }
.dh-card-img-wrap {
  position: relative; width: 100%;
  padding-top: 56.25%; overflow: hidden;
  background: linear-gradient(135deg, #e0e0e0, #f0f0f0);
}
[data-theme="dark"] .dh-card-img-wrap {
  background: linear-gradient(135deg, #21262d, #1a1f26);
}
.dh-card-img-wrap img {
  position: absolute; top: 0; left: 0;
  width: 100%; height: 100%; object-fit: cover;
  transition: transform 0.5s ease;
}
.dh-card:hover .dh-card-img-wrap img { transform: scale(1.06); }

.dh-card-badge {
  display: inline-flex; padding: 4px 10px; border-radius: 6px;
  font-family: var(--font-en); font-size: 10px; font-weight: 700;
  letter-spacing: 0.8px; text-transform: uppercase;
  color: #fff; background: var(--badge-latest);
  position: absolute; top: 12px; left: 12px; z-index: 3;
  box-shadow: 0 2px 8px rgba(0,0,0,0.2);
}
.dh-card-body { padding: 16px 18px 18px; }
.dh-card-source {
  display: flex; align-items: center; gap: 6px; margin-bottom: 8px;
}
.dh-card-source-dot {
  width: 18px; height: 18px; border-radius: 50%;
  background: var(--accent-gradient);
}
.dh-card-source-name {
  font-family: var(--font-en); font-size: 11px; font-weight: 600;
  color: var(--accent); text-transform: uppercase; letter-spacing: 0.5px;
}
.dh-card-title {
  font-size: 17px; font-weight: 700; line-height: 1.45;
  color: var(--text-primary); margin-bottom: 8px;
  display: -webkit-box; -webkit-line-clamp: 3;
  -webkit-box-orient: vertical; overflow: hidden;
  transition: color var(--transition);
}
.dh-card:hover .dh-card-title { color: var(--accent); }
.dh-card-snippet {
  font-size: 13.5px; color: var(--text-secondary);
  line-height: 1.55;
  display: -webkit-box; -webkit-line-clamp: 2;
  -webkit-box-orient: vertical; overflow: hidden;
  margin-bottom: 14px;
}
.dh-card-meta {
  display: flex; align-items: center; justify-content: space-between;
  font-family: var(--font-en); font-size: 11.5px; color: var(--text-muted);
}
.dh-card-meta-left { display: flex; align-items: center; gap: 12px; }
.dh-card-meta-item { display: flex; align-items: center; gap: 4px; }
.dh-card-meta-item .material-icons-round { font-size: 15px; }
.dh-card-share-btn {
  width: 32px; height: 32px; border-radius: 50%;
  border: none; background: transparent; color: var(--text-muted);
  cursor: pointer; display: flex; align-items: center;
  justify-content: center; transition: all var(--transition);
}
.dh-card-share-btn:hover { background: var(--bg-primary); color: var(--accent); }

/* ===== POST PAGE ===== */
.dh-post-wrap {
  max-width: 800px; margin: 0 auto; padding: 24px 16px;
}
.dh-post-hero {
  width: 100%; border-radius: var(--radius);
  overflow: hidden; margin-bottom: 24px;
  box-shadow: var(--shadow-md);
}
.dh-post-hero img { width: 100%; max-height: 480px; object-fit: cover; }
.dh-post-title {
  font-size: 28px; font-weight: 800;
  line-height: 1.35; margin-bottom: 16px;
}
.dh-post-meta-bar {
  display: flex; align-items: center; gap: 16px;
  padding: 14px 0;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  margin-bottom: 24px;
  font-family: var(--font-en); font-size: 12px; color: var(--text-muted);
}
.dh-post-content { font-size: 17px; line-height: 1.85; }
.dh-post-content p { margin-bottom: 18px; }
.dh-post-content img { border-radius: var(--radius-sm); margin: 20px 0; }
.dh-post-labels {
  display: flex; flex-wrap: wrap; gap: 8px;
  margin-top: 30px; padding-top: 20px;
  border-top: 1px solid var(--border);
}
.dh-tag {
  padding: 6px 14px; border-radius: 20px;
  background: var(--bg-primary);
  font-size: 12px; font-weight: 600; color: var(--text-secondary);
  transition: all var(--transition);
}
.dh-tag:hover { background: var(--accent); color: #fff; }

/* ===== STATIC PAGE ===== */
.dh-static-page {
  background: var(--bg-card); border-radius: var(--radius);
  padding: 30px; box-shadow: var(--shadow-sm);
  border: 1px solid var(--border);
  max-width: 800px; margin: 24px auto;
}

/* ===== PAGINATION ===== */
.dh-pagination {
  display: flex; justify-content: center; gap: 8px; padding: 30px 0;
}
.dh-pagination a {
  padding: 10px 18px; border-radius: var(--radius-sm);
  background: var(--bg-card); border: 1px solid var(--border);
  font-family: var(--font-en); font-size: 13px; font-weight: 600;
  color: var(--text-secondary); transition: all var(--transition);
}
.dh-pagination a:hover {
  background: var(--accent); color: #fff; border-color: var(--accent);
}

/* ===== SHARE BAR ===== */
.dh-share-bar {
  display: flex; gap: 10px; margin-top: 24px; flex-wrap: wrap;
}
.dh-share-btn {
  padding: 8px 16px; border-radius: 20px;
  font-size: 12px; font-weight: 600; color: #fff;
  transition: all var(--transition);
}
.dh-share-btn:hover { opacity: 0.85; transform: translateY(-2px); }
.dh-share-fb { background: #1877f2; }
.dh-share-tw { background: #1da1f2; }
.dh-share-wa { background: #25d366; }

/* ===== FOOTER ===== */
.dh-footer {
  background: var(--bg-card);
  border-top: 1px solid var(--border);
  padding: 40px 20px 24px; margin-top: 40px;
}
.dh-footer-inner { max-width: 1280px; margin: 0 auto; text-align: center; }
.dh-footer-logo {
  font-family: var(--font-en); font-size: 24px; font-weight: 800;
  background: var(--accent-gradient);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  background-clip: text; margin-bottom: 12px;
}
.dh-footer-text { font-size: 13px; color: var(--text-muted); margin-bottom: 20px; }
.dh-footer-links {
  display: flex; justify-content: center; gap: 24px; flex-wrap: wrap;
}
.dh-footer-link {
  font-size: 13px; color: var(--text-secondary);
  font-weight: 500; transition: color var(--transition);
}
.dh-footer-link:hover { color: var(--accent); }
.dh-footer-copy {
  margin-top: 24px; padding-top: 20px;
  border-top: 1px solid var(--border);
  font-family: var(--font-en); font-size: 12px; color: var(--text-muted);
}

/* ===== BACK TO TOP ===== */
.dh-back-top {
  position: fixed; bottom: 24px; right: 24px;
  width: 48px; height: 48px; border-radius: 50%;
  background: var(--accent-gradient); color: #fff;
  border: none; cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  box-shadow: 0 4px 20px rgba(230,57,70,0.4);
  opacity: 0; transform: translateY(20px);
  transition: all var(--transition); z-index: 999;
}
.dh-back-top.visible { opacity: 1; transform: translateY(0); }
.dh-back-top:hover { transform: translateY(-3px) scale(1.05); }

/* ===== SEARCH OVERLAY ===== */
.dh-search-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.6); backdrop-filter: blur(8px);
  z-index: 2000; display: none;
  align-items: flex-start; justify-content: center;
  padding-top: 120px;
}
.dh-search-overlay.active { display: flex; }
.dh-search-box {
  background: var(--bg-card); border-radius: var(--radius);
  padding: 8px; width: 90%; max-width: 600px;
  box-shadow: var(--shadow-lg);
  display: flex; align-items: center; gap: 8px;
  animation: slideDown 0.3s ease;
}
@keyframes slideDown {
  from { opacity: 0; transform: translateY(-20px); }
  to { opacity: 1; transform: translateY(0); }
}
.dh-search-input {
  flex: 1; border: none; outline: none;
  padding: 12px 16px; font-size: 16px;
  font-family: var(--font-ml); background: transparent;
  color: var(--text-primary);
}
.dh-search-submit {
  width: 44px; height: 44px; border-radius: 12px;
  border: none; background: var(--accent-gradient);
  color: #fff; cursor: pointer;
  display: flex; align-items: center; justify-content: center;
}

/* ===== COMMENTS ===== */
.dh-comments { margin-top: 40px; }
.dh-comments h3 {
  font-size: 18px; font-weight: 700;
  margin-bottom: 16px; padding-bottom: 10px;
  border-bottom: 3px solid var(--accent);
  display: inline-block;
}

/* ===== 404 ===== */
.dh-error {
  text-align: center; padding: 80px 20px;
}
.dh-error-code {
  font-size: 80px; font-weight: 800;
  background: var(--accent-gradient);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  font-family: var(--font-en);
}

/* ===== RESPONSIVE ===== */
@media (max-width: 768px) {
  .dh-grid { grid-template-columns: 1fr; gap: 16px; }
  .dh-grid .dh-card:first-child .dh-card-img-wrap { padding-top: 56%; }
  .dh-grid .dh-card:first-child .dh-card-title { font-size: 20px; }
  .dh-post-title { font-size: 22px; }
  .dh-card-title { font-size: 15.5px; }
  .dh-header-inner { padding: 10px 14px; }
}
@media (max-width: 480px) {
  .dh-card-body { padding: 12px 14px 14px; }
}

body.script:
//
// Dark mode
(function(){
  var t=document.getElementById('themeToggle');
  var ic=t.querySelector('.material-icons-round');
  var s=localStorage.getItem('dh-theme');
  if(s==='dark'||(!s&&window.matchMedia('(prefers-color-scheme:dark)').matches)){
    document.body.setAttribute('data-theme','dark');ic.textContent='light_mode';
  }
  t.addEventListener('click',function(){
    var d=document.body.getAttribute('data-theme')==='dark';
    if(d){document.body.removeAttribute('data-theme');ic.textContent='dark_mode';localStorage.setItem('dh-theme','light');}
    else{document.body.setAttribute('data-theme','dark');ic.textContent='light_mode';localStorage.setItem('dh-theme','dark');}
  });
})();

// Back to top
window.addEventListener('scroll',function(){
  var b=document.getElementById('backToTop');
  if(window.scrollY>400)b.classList.add('visible');
  else b.classList.remove('visible');
});

// Ticker
(function(){
  var el=document.getElementById('tickerContent');
  if(!el)return;
  var titles=document.querySelectorAll('.dh-card-title');
  var h='';
  titles.forEach(function(t){h+='<span class="dh-ticker-item">'+t.textContent.trim()+'</span>';});
  el.innerHTML=h+h;
})();

// Card animations
(function(){
  if(!('IntersectionObserver' in window))return;
  var cards=document.querySelectorAll('.dh-card');
  cards.forEach(function(c,i){
    c.style.opacity='0';c.style.transform='translateY(30px)';
    c.style.transition='opacity 0.5s ease '+(i*0.08)+'s, transform 0.5s ease '+(i*0.08)+'s';
  });
  var obs=new IntersectionObserver(function(entries){
    entries.forEach(function(e){
      if(e.isIntersecting){e.target.style.opacity='1';e.target.style.transform='translateY(0)';obs.unobserve(e.target);}
    });
  },{rootMargin:'50px',threshold:0.1});
  cards.forEach(function(c){obs.observe(c);});
})();

// Fix thumbnail URLs to high-res
(function(){
  var imgs=document.querySelectorAll('.dh-card-img-wrap img');
  imgs.forEach(function(img){
    var s=img.src||img.getAttribute('src');
    if(s && s.indexOf('s72-c')!==-1){
      img.src=s.replace(/\/s72-c\//,'/s680/').replace(/=s72-c/,'=s680');
    }
    if(s && s.indexOf('/s72-c/')!==-1){
      img.src=s.replace('/s72-c/','/w680/');
    }
  });
})();
//
